import{_ as t,o as i,c as a,ag as n}from"./chunks/framework.eQLvDOR_.js";const g=JSON.parse('{"title":"Set up your coding assistant with Gemini MCP and Skills  |  Gemini API","description":"","frontmatter":{"title":"Set up your coding assistant with Gemini MCP and Skills  |  Gemini API","source":"https://ai.google.dev/gemini-api/docs/coding-agents","category":"[AI_IDE_And_CLI]","clipped_at":"2026-04-04","tags":["ai-ide-and-cli"],"status":"distilled","compiled":true},"headers":[],"relativePath":"library/AI_IDE_And_CLI/AI_IDE_And_CLI - Set up your coding assistant with Gemini MCP and Skills  _  Gemini API.md","filePath":"library/AI_IDE_And_CLI/AI_IDE_And_CLI - Set up your coding assistant with Gemini MCP and Skills  _  Gemini API.md","lastUpdated":null}'),s={name:"library/AI_IDE_And_CLI/AI_IDE_And_CLI - Set up your coding assistant with Gemini MCP and Skills  _  Gemini API.md"};function o(l,e,r,d,c,h){return i(),a("div",null,[...e[0]||(e[0]=[n('<p>Try the new high-speed, cost-effective <a href="https://ai.google.dev/gemini-api/docs/models/veo-3.1-lite-generate-preview" target="_blank" rel="noreferrer">Veo 3.1 Lite</a> model for video generation at scale.</p><p>AI coding assistants are powerful but have limitations—training data cuts off at a specific date, missing new API features and changes. Without access to Gemini-specific documentation, agents may suggest generic patterns instead of optimized approaches.</p><p>To keep your coding assistant current with the evolving Gemini API and its recommended usage, we recommend setting up the <strong>Gemini Docs MCP</strong> and enhancing your environment with <strong>Gemini API Skills</strong>. While these tools are usable independently, they are designed to work together to provide complete coverage.</p><h2 id="connect-the-gemini-docs-mcp" tabindex="-1">Connect the Gemini Docs MCP <a class="header-anchor" href="#connect-the-gemini-docs-mcp" aria-label="Permalink to &quot;Connect the Gemini Docs MCP&quot;">​</a></h2><p>Gemini hosts a public Model Context Protocol (MCP) server at <code>https://gemini-api-docs-mcp.dev</code>. Connecting your coding agent to this server ensures that all queries have access to the latest APIs, code updates, and optimal configuration examples.</p><p>Run the following command in your agent&#39;s terminal or project root to install the server:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>npx add-mcp &quot;https://gemini-api-docs-mcp.dev&quot;</span></span></code></pre></div><p>This server adds a <code>search_documentation</code> function that your agent can use to retrieve real-time API definitions and integration patterns from the official Gemini documentation files.</p><h2 id="add-api-development-skills" tabindex="-1">Add API Development Skills <a class="header-anchor" href="#add-api-development-skills" aria-label="Permalink to &quot;Add API Development Skills&quot;">​</a></h2><p>The skills provide <strong>baked-in rules and best practices</strong> (such as enforcing the correct SDK and current model versions) directly in your assistant&#39;s context. The skill works together with the Gemini Docs MCP service: If you have both installed, the skill uses the MCP service for documentation, but even without the MCP installed, it will fetch <code>llms.txt</code> from <code>ai.google.dev</code> as a fallback.</p><p>To install these skills, you can use one of the following supported tools. Installation instructions for both are provided below each skill module:</p><ul><li><strong><a href="https://skills.sh/" target="_blank" rel="noreferrer">skills.sh</a></strong>: Recommended. The open standard for portable agent behaviors.</li><li><strong><a href="https://context7.com/" target="_blank" rel="noreferrer">Context7</a></strong>: Supported for users already utilizing the Context7 ecosystem.</li></ul><h3 id="gemini-api-dev" tabindex="-1">gemini-api-dev <a class="header-anchor" href="#gemini-api-dev" aria-label="Permalink to &quot;gemini-api-dev&quot;">​</a></h3><p>The foundational skill for general-purpose Gemini development. This skill provides documentation and best practices for:</p><ul><li>Prompt routing to current models (e.g., Gemini 3.1 Pro/Flash) and avoiding deprecated models</li><li>Multimodal prompting, function calling, structured outputs, and common integration patterns</li></ul><h4 id="install-with-skills-sh" tabindex="-1">Install with skills.sh <a class="header-anchor" href="#install-with-skills-sh" aria-label="Permalink to &quot;Install with skills.sh&quot;">​</a></h4><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>npx skills add google-gemini/gemini-skills --skill gemini-api-dev --global</span></span></code></pre></div><h4 id="install-with-context7" tabindex="-1">Install with Context7 <a class="header-anchor" href="#install-with-context7" aria-label="Permalink to &quot;Install with Context7&quot;">​</a></h4><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>npx ctx7 skills install /google-gemini/gemini-skills gemini-api-dev</span></span></code></pre></div><h3 id="gemini-live-api-dev" tabindex="-1">gemini-live-api-dev <a class="header-anchor" href="#gemini-live-api-dev" aria-label="Permalink to &quot;gemini-live-api-dev&quot;">​</a></h3><p>Skill for building real-time conversational AI applications with Gemini Live API. This skill provides documentation and best practices for:</p><ul><li>WebSocket connections for low-latency streaming</li><li>Streaming audio, video, and text</li><li>Voice activity detection and barge-in support</li></ul><h4 id="install-with-skills-sh-1" tabindex="-1">Install with skills.sh <a class="header-anchor" href="#install-with-skills-sh-1" aria-label="Permalink to &quot;Install with skills.sh&quot;">​</a></h4><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>npx skills add google-gemini/gemini-skills --skill gemini-live-api-dev --global</span></span></code></pre></div><h4 id="install-with-context7-1" tabindex="-1">Install with Context7 <a class="header-anchor" href="#install-with-context7-1" aria-label="Permalink to &quot;Install with Context7&quot;">​</a></h4><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>npx ctx7 skills install /google-gemini/gemini-skills gemini-live-api-dev</span></span></code></pre></div><p>Skill for building apps with the <a href="https://ai.google.dev/gemini-api/docs/interactions" target="_blank" rel="noreferrer">Interactions API</a>. The Interactions API is a unified interface for interacting with Gemini models and agents, designed for agentic applications. This skill covers:</p><ul><li>Text generation, multi-turn chat, and streaming</li><li>Function calling, structured output, and image generation</li><li>Background execution and Deep Research agents</li><li>Server-side conversation state management</li><li>Python and TypeScript SDK patterns</li></ul><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>npx skills add google-gemini/gemini-skills --skill gemini-interactions-api --global</span></span></code></pre></div><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>npx ctx7 skills install /google-gemini/gemini-skills gemini-interactions-api</span></span></code></pre></div><h2 id="verify-installation" tabindex="-1">Verify installation <a class="header-anchor" href="#verify-installation" aria-label="Permalink to &quot;Verify installation&quot;">​</a></h2><p>After installing, confirm that your coding assistant can connect to the Gemini Docs MCP server and use your installed skills.</p><h3 id="_1-verify-agent-behavior" tabindex="-1">1. Verify agent behavior <a class="header-anchor" href="#_1-verify-agent-behavior" aria-label="Permalink to &quot;1\\. Verify agent behavior&quot;">​</a></h3><p>The most reliable way to verify is to ask your agent a technical question about Gemini API.</p><p><strong>Prompt:</strong> &quot;How do I use context caching with the Gemini API?&quot;</p><p>A successful setup will:</p><ul><li><strong>Provide accurate code</strong>: Reference specific Gemini methods like <code>cacheContent</code> or <code>cachedContents.create</code> from the latest endpoints.</li><li><strong>Use the MCP Tool</strong>: Show that it is connected to the <strong>Gemini Docs MCP Server</strong> or utilizing the <code>search_documentation</code> tool to fetch data.</li><li><strong>Invoke loaded skills</strong>: Show an indicator that it is &quot;Using skill: gemini-api-dev&quot; (if relying on a secondary wrapper).</li></ul><h3 id="_2-verify-manifestations-tools" tabindex="-1">2. Verify manifestations &amp; tools <a class="header-anchor" href="#_2-verify-manifestations-tools" aria-label="Permalink to &quot;2\\. Verify manifestations &amp; tools&quot;">​</a></h3><p>If the agent gives a general or generic answer, use the specific Discovery or Status commands for your environment to verify that the Docs MCP or skill is loaded into memory.</p><table tabindex="0"><thead><tr><th>Environment</th><th>MCP Verification</th><th>Skills Verification</th></tr></thead><tbody><tr><td><strong>Claude Code</strong></td><td>Type <code>/mcp</code> in the terminal to view active servers and <code>search_documentation</code> tools.</td><td>Type <code>/skills</code> in the terminal to list all active manifests.</td></tr><tr><td><strong>Cursor</strong></td><td>Navigate to <strong>Settings &gt; Features &gt; MCP</strong>. Ensure server is &quot;Connected&quot;.</td><td>Open <strong>Settings &gt; Rules</strong>. Verify the skill appears under &quot;Agent Decides.&quot;</td></tr><tr><td><strong>Antigravity</strong></td><td>Check the <strong>Customizations &gt; Connections</strong> sidebar for MCP status.</td><td>Type <code>/skills list</code> or check the <strong>Customizations &gt; Rules</strong> sidebar.</td></tr><tr><td><strong>Gemini CLI</strong></td><td>Run <code>gemini mcp list</code> or use <code>/mcp list</code>.</td><td>Run <code>gemini skills list</code> or use the <code>/skills</code> slash command in-session.</td></tr><tr><td><strong>Copilot</strong></td><td>Type <code>@gemini /mcp</code> to list active data connectors.</td><td>Type <code>@gemini /skills</code> (or <code>/skills</code>) to view active extensions.</td></tr></tbody></table><h2 id="troubleshooting" tabindex="-1">Troubleshooting <a class="header-anchor" href="#troubleshooting" aria-label="Permalink to &quot;Troubleshooting&quot;">​</a></h2><p>If your agent provides only general information or fails to recognize Gemini-specific methods, check the following:</p><h3 id="agent-didn-t-discover-the-skill" tabindex="-1">Agent didn&#39;t discover the skill <a class="header-anchor" href="#agent-didn-t-discover-the-skill" aria-label="Permalink to &quot;Agent didn&#39;t discover the skill&quot;">​</a></h3><p>Most agents index skills only on startup.</p><p><strong>Fix:</strong> Completely restart your IDE (Cursor/VS Code) or exit and re-open your terminal-based agent (Claude Code).</p><h3 id="global-vs-local-conflict" tabindex="-1">Global vs. local conflict <a class="header-anchor" href="#global-vs-local-conflict" aria-label="Permalink to &quot;Global vs. local conflict&quot;">​</a></h3><p>If you installed with the <code>--global</code> flag, your agent might be ignoring it in favor of project-specific rules.</p><p><strong>Fix:</strong> Try installing the skill directly into your project root without the global flag:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>npx skills add google-gemini/gemini-skills --skill gemini-api-dev</span></span></code></pre></div>',49)])])}const u=t(s,[["render",o]]);export{g as __pageData,u as default};
